}

type LobbyStatus = 'online' | 'full' | 'offline'

type LobbySummary = {
  id: string
  name: string
  region: string
  description: string
  status: LobbyStatus
  maxPlayers: number
  playerCount: number
  populationCount: number
  playersOnline: number
