function formatValidationErrors(errors: ApiValidationError[] | undefined): string[] {
  if (!errors || errors.length === 0) return []
  return errors.map((error) => {
    const path = Array.isArray(error.loc) ? error.loc.join('.') : 'field'
    const message = error.msg ?? 'Invalid value'
    return `${path}: ${message}`
  })
}

function extractErrorMessage(payload: ApiErrorPayload | null): string {
  if (payload?.detail) return payload.detail
  if (payload?.errors && payload.errors.length > 0) return 'Validation failed'
  return 'Request failed'
}

function normalizeAuthCsrfSnapshot(value: AuthCsrfSnapshot): AuthCsrfSnapshot {
  return {
    csrf_access_token: typeof value.csrf_access_token === 'string' ? value.csrf_access_token : '',
    csrf_refresh_token: typeof value.csrf_refresh_token === 'string' ? value.csrf_refresh_token : '',
    anon_csrf: typeof value.anon_csrf === 'string' ? value.anon_csrf : '',
  }
}

async function authRequest<T>(path: string, init: RequestInit): Promise<T> {
  assertSecureAuthTransport()
  const response = await fetchWithTimeout(
    `${AUTH_BASE_URL}${path}`,
    {
      ...init,
      credentials: 'include',
      headers: {
        'Content-Type': 'application/json',
        ...(init.headers ?? {}),
      },
    },
    AUTH_REQUEST_TIMEOUT_MS,
  )

  const payload = (await parseJsonSafe(response)) as ApiErrorPayload | T | null

  if (!response.ok) {
    const errorPayload = (payload as ApiErrorPayload) ?? null
    throw new AuthApiError(extractErrorMessage(errorPayload), response.status, errorPayload)
  }

  return payload as T
}

export async function getAnonCsrfToken(): Promise<string> {
  const data = await authRequest<CsrfResponse>('/csrf-token', { method: 'GET' })
  return data.csrf_token
}

async function requestAuthCsrfSnapshot(force = false): Promise<AuthCsrfSnapshot> {
  if (!force && cachedAuthCsrfSnapshot) return cachedAuthCsrfSnapshot
  const snapshot = normalizeAuthCsrfSnapshot(await authRequest<AuthCsrfSnapshot>('/csrf', { method: 'GET' }))
  cachedAuthCsrfSnapshot = snapshot
  return snapshot
}

export async function login(payload: LoginRequest): Promise<LoginResponse> {
  const csrfToken = await getAnonCsrfToken()
  const response = await authRequest<LoginResponse>('/login', {
    method: 'POST',
    headers: {
      'X-CSRF-TOKEN': csrfToken,
    },
    body: JSON.stringify(payload),
  })
  cachedAuthCsrfSnapshot = null
  void requestAuthCsrfSnapshot(true).catch(() => {})
  return response
}

export async function register(payload: RegisterRequest): Promise<RegisterResponse> {
  const csrfToken = await getAnonCsrfToken()
  return authRequest<RegisterResponse>('/register', {
    method: 'POST',
    headers: {
      'X-CSRF-TOKEN': csrfToken,
    },
    body: JSON.stringify(payload),
  })
}

export function beginGoogleSignIn(): void {
  assertSecureAuthTransport()
  window.location.assign(`${AUTH_BASE_URL}/google/login`)
}

export async function getAccessCsrfToken(): Promise<string> {
  const token = readCookie('csrf_access_token') || cachedAuthCsrfSnapshot?.csrf_access_token
  if (!token) {
    const snapshot = await requestAuthCsrfSnapshot()
    if (snapshot.csrf_access_token) return snapshot.csrf_access_token
    throw new AuthApiError('Your session has expired. Please sign in again.', 401, null)
  }
  return token
}

async function getRefreshCsrfToken(): Promise<string> {
  const token = readCookie('csrf_refresh_token') || cachedAuthCsrfSnapshot?.csrf_refresh_token
  if (!token) {
    const snapshot = await requestAuthCsrfSnapshot()
    if (snapshot.csrf_refresh_token) return snapshot.csrf_refresh_token
    throw new AuthApiError('Your session has expired. Please sign in again.', 401, null)
  }
  return token
}

async function refreshAccessToken(): Promise<void> {
  const refreshCsrfToken = await getRefreshCsrfToken()
  cachedAuthCsrfSnapshot = null
  await authRequest<{ message: string }>('/refresh', {
    method: 'POST',
    headers: {
      'X-CSRF-TOKEN': refreshCsrfToken,
    },
  })
}

async function requestCurrentUserWithAccessCsrf(csrfToken: string): Promise<UserResponse> {
  return authRequest<UserResponse>('/me', {
    method: 'GET',
    headers: {
      'X-CSRF-TOKEN': csrfToken,
    },
  })
}

