  byBuildId: Record<string, ImageBitmap[]>
  conveyor: ImageBitmap[]
  miner: ImageBitmap[]
  drill: ImageBitmap[]
  hub: ImageBitmap[]
}

export const BUILDING_SPRITE_DEFINITION: BuildingSpriteDefinition = {
  byBuildId: {
    battery: [batteryTileAsset],
    splitter: [splitterTileAsset],
    storage: [storageTileAsset],
    smelter: [smelterTileAsset],
    generator: [generatorTileAsset],
    logistics_hub: [logisticsHubTileAsset],
  },
  conveyor: [conveyorTileAsset],
  miner: [minerTileAsset],
  drill: [drillTileAsset],
  hub: [logisticsHubTileAsset],
}

export async function loadBuildingSpriteBitmaps(
  definition: BuildingSpriteDefinition = BUILDING_SPRITE_DEFINITION,
): Promise<BuildingSpriteBitmaps | null> {
  const byBuildId: Record<string, ImageBitmap[]> = {}
  let loadedCount = 0

  for (const [buildId, urls] of Object.entries(definition.byBuildId)) {
    const bitmaps = await loadBitmapList(urls ?? [])
    byBuildId[buildId] = bitmaps
    loadedCount += bitmaps.length
  }

  const conveyor = await loadBitmapList(definition.conveyor ?? [])
  const miner = await loadBitmapList(definition.miner ?? [])
  const drill = await loadBitmapList(definition.drill ?? [])
  const hub = await loadBitmapList(definition.hub ?? [])
  loadedCount += conveyor.length + miner.length + drill.length + hub.length

  if (loadedCount === 0) return null

  return {
    byBuildId,
    conveyor,
    miner,
    drill,
    hub,
  }
}

export function closeBuildingSpriteBitmaps(bitmaps: BuildingSpriteBitmaps | null): void {
  if (!bitmaps) return
  for (const variants of Object.values(bitmaps.byBuildId)) {
    closeBitmapList(variants)
  }
  closeBitmapList(bitmaps.conveyor)
  closeBitmapList(bitmaps.miner)
  closeBitmapList(bitmaps.drill)
  closeBitmapList(bitmaps.hub)
}

export function pickBuildingSpriteByBuildId(
  bitmaps: BuildingSpriteBitmaps | null,
  buildId: string,
): ImageBitmap | null {
  if (!bitmaps) return null
  const variants = bitmaps.byBuildId[buildId]
  if (!variants || variants.length === 0) return null
  return variants[0] ?? null
}

export function pickConveyorSprite(bitmaps: BuildingSpriteBitmaps | null): ImageBitmap | null {
  if (!bitmaps || bitmaps.conveyor.length === 0) return null
  return bitmaps.conveyor[0] ?? null
}

export function pickMinerSprite(bitmaps: BuildingSpriteBitmaps | null, kind: 'miner' | 'drill'): ImageBitmap | null {
  if (!bitmaps) return null
  const variants = kind === 'drill' ? bitmaps.drill : bitmaps.miner
  if (variants.length === 0) return null
  return variants[0] ?? null
}

export function pickHubSprite(bitmaps: BuildingSpriteBitmaps | null): ImageBitmap | null {
  if (!bitmaps || bitmaps.hub.length === 0) return null
  return bitmaps.hub[0] ?? null
}
import valleyTileAsset from '../../../assets/valley1.png'
import {
  closeBitmapList,
  loadBitmapList,
} from './spriteUtils'

export type TerrainTilesetDefinition = {
  sourcePx: number
  accessible: Record<number, string[]>
  blocked: string[]
}

export type TerrainTilesetBitmaps = {
  sourcePx: number
  accessible: Record<number, ImageBitmap[]>
  blocked: ImageBitmap[]
}

export const TERRAIN_TILESET_DEFINITION: TerrainTilesetDefinition = {
  sourcePx: 24,
  accessible: {
    1: [valleyTileAsset],
    2: [valleyTileAsset],
    3: [valleyTileAsset],
    4: [valleyTileAsset],
  },
  blocked: [],
}

export async function loadTerrainTilesetBitmaps(
  definition: TerrainTilesetDefinition = TERRAIN_TILESET_DEFINITION,
): Promise<TerrainTilesetBitmaps | null> {
  const accessible: Record<number, ImageBitmap[]> = { 1: [], 2: [], 3: [], 4: [] }

  for (const valley of [1, 2, 3, 4]) {
    const urls = definition.accessible[valley] ?? []
    accessible[valley] = await loadBitmapList(urls)
  }

  const blocked = await loadBitmapList(definition.blocked ?? [])
  const loadedCount =
    blocked.length + accessible[1].length + accessible[2].length + accessible[3].length + accessible[4].length

  if (loadedCount === 0) return null

  return {
    sourcePx: definition.sourcePx,
    accessible,
    blocked,
  }
}

export function closeTerrainTilesetBitmaps(tileset: TerrainTilesetBitmaps | null): void {
  if (!tileset) return
  closeBitmapList(tileset.blocked)
  closeBitmapList(tileset.accessible[1] ?? [])
  closeBitmapList(tileset.accessible[2] ?? [])
  closeBitmapList(tileset.accessible[3] ?? [])
  closeBitmapList(tileset.accessible[4] ?? [])
}

export function pickTerrainTilesetVariant(
  tileset: TerrainTilesetBitmaps | null,
  _x: number,
  _y: number,
  valley: number,
): ImageBitmap | null {
  if (!tileset) return null
  const variants = valley <= 0 ? tileset.blocked : (tileset.accessible[valley] ?? tileset.accessible[1] ?? [])
  if (!variants || variants.length === 0) return null
  return variants[0] ?? null
}

